pub fn to_knowledge_entry(&self) -> KnowledgeEntry {
        let content = format!(
            "[{}] {}\nTargets: {}\nConfidence: {:.0}%",
            self.check_type.as_str(),
            self.rationale,
            self.target_ids
                .iter()
                .map(|id| id.to_string())
                .collect::<Vec<_>>()
                .join(", "),
            self.confidence * 100.0,
        );
        let mut entry = KnowledgeEntry::new(
            content,
            self.scope_id.clone(),
            "reasoner".to_string(),
        );
        entry.metadata.chunk_type = Some("finding".to_string());
        entry
    }
